INSERT INTO `CompanyRisks` VALUES (1,2,'Reputation Risk','A negative reputation due to low-quality or offensive content could hinder member acquisition/retention, attract regulatory scrutiny, and harm operating results.',1,23,NULL,NULL,0,NULL,NULL),(2,2,'Acquisition and investment integration risks','Acquisitions may be difficult to integrate, may inherit liabilities, fail to realize expected benefits, and distract management, potentially harming business performance.',1,23,NULL,NULL,0,NULL,NULL),(3,2,'Failure to complete or integrate acquisitions','If an announced acquisition is not completed or integrated successfully, the expected benefits may not be realized, impacting the business negatively.',1,23,NULL,NULL,0,NULL,NULL),(4,4,'Quarterly financial fluctuations from acquisitions','Acquisitions can cause fluctuations in quarterly financial results due to transaction-related costs, charges, and write-offs, negatively impacting financial results.',1,23,NULL,NULL,0,NULL,NULL),(5,2,'Supply and pricing risk from single or limited sources','The Company depends on single or limited sources for certain components, exposing it to supply shortages and price increases that could materially adversely affect its business.',1,1,NULL,NULL,0,NULL,NULL),(6,2,'Dependence on Third-Party Software Developers','The Company\'s hardware sales depend on the availability and quality of third-party software applications. If developers discontinue support or focus on competitors\' platforms with larger market share, customer demand for the Company\'s products may decline, adversely impacting financial performance.',1,1,NULL,NULL,0,NULL,NULL),(7,2,'Data Security and Cyber Attacks','Losses or unauthorized access to confidential information, including personal and health data, as well as malicious attacks, could harm the Company\'s reputation, operations, financial condition, and stock price, and may lead to litigation or regulatory penalties.',1,1,NULL,NULL,0,NULL,NULL),(8,2,'Investment and acquisition risks','The company faces risks from investing in new business strategies, commercial relationships, and acquisitions, including management distraction, unexpected liabilities, regulatory challenges, inadequate returns, asset impairment, and failure to obtain approvals or counterparty performance.',1,1,NULL,NULL,0,NULL,NULL),(9,4,'Interest Rate Risk','Fluctuations in U.S. interest rates can negatively affect the fair value of the company\'s investment portfolio and increase interest expense on its term debt.',1,1,NULL,NULL,0,NULL,NULL),(10,2,'Aggressive pricing by competitors like Intel','Intel uses its microprocessor market position to price products aggressively and target our customers with special incentives, potentially reducing our unit sales and average selling prices.',1,43,NULL,NULL,0,NULL,'Item 1A. Risk Factors'),(11,2,'Nvidia\'s ecosystem influence','Nvidia leverages its market position in data center GPU, financial resources, and proprietary software ecosystem to influence customers, potentially limiting our sales.',1,43,NULL,NULL,0,NULL,'Nvidia Corporation (Nvidia) leverages its market position in data center GPU, financial resources, and proprietary software ecosystem to promote its systems and influences customers who do business with us. (Item 1A)'),(12,1,'Strategic partnerships among competitors','Partnerships like Nvidia-Intel may increase competition and pricing pressure for our products.',1,43,NULL,NULL,0,NULL,'In September 2025, Nvidia announced a partnership and investment in Intel to partner on new data center and client platform products. This partnership may result in increased competition and pricing pressure for our products or could prevent us from participating in other opportunities, which could materially adversely impact our business, financial condition and margins. (Item 1A)'),(13,1,'Alternative computing architectures','Competitors pursuing Arm architecture could grow the Arm ecosystem and increase competition in consumer, commercial and data center, reducing demand for our products.',1,43,NULL,NULL,0,NULL,'Some competitors are pursuing alternative computing architectures, such as Arm, which could grow the Arm ecosystem and increase competition in consumer, commercial and data center, reducing demand for our products. (Item 1A)');
/*!40000 ALTER TABLE `CompanyRisks` ENABLE KEYS */;
