  `DataSource` int DEFAULT NULL,
  `CompanyId` bigint NOT NULL,
  `RelatedCompanyId` bigint DEFAULT NULL,
  `DeletedAt` datetime(6) DEFAULT NULL,
  `ContributedByUserId` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `Status` int NOT NULL DEFAULT '0',
  `SupersedesId` bigint DEFAULT NULL,
  `Reference` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  PRIMARY KEY (`Id`),
  KEY `IX_CostSources_CompanyId` (`CompanyId`),
  KEY `IX_CostSources_RelatedCompanyId` (`RelatedCompanyId`),
  KEY `IX_CostSources_ContributedByUserId` (`ContributedByUserId`),
  CONSTRAINT `FK_CostSources_AspNetUsers_ContributedByUserId` FOREIGN KEY (`ContributedByUserId`) REFERENCES `AspNetUsers` (`Id`) ON DELETE SET NULL,
  CONSTRAINT `FK_CostSources_Companies_CompanyId` FOREIGN KEY (`CompanyId`) REFERENCES `Companies` (`Id`) ON DELETE CASCADE,
  CONSTRAINT `FK_CostSources_Companies_RelatedCompanyId` FOREIGN KEY (`RelatedCompanyId`) REFERENCES `Companies` (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=207 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
