INSERT INTO `CountryAdvantages` VALUES (1,1,'Tech dominance ÔÇö home to the world\'s largest tech companies (Apple, Microsoft, Nvidia, Google)',1,NULL),(2,1,'USD reserve currency status underpins global trade and gives the US unique borrowing advantages',1,NULL),(3,1,'Deep, liquid capital markets ÔÇö NYSE and NASDAQ are the world\'s largest equity exchanges',1,NULL),(4,1,'Military and diplomatic reach provides geopolitical stability and enforces trade agreements',1,NULL),(5,1,'Energy independence achieved through shale revolution ÔÇö largest oil & gas producer globally',1,NULL),(6,1,'Silicon Valley innovation ecosystem continuously generates world-leading startups and IP',1,NULL),(7,2,'Engineering excellence ÔÇö world-class manufacturing in automotive, machinery and chemicals',2,NULL),(8,2,'Export competitiveness driven by the \'Mittelstand\' ÔÇö highly productive SME industrial base',2,NULL),(9,2,'EU single market access provides a home market of 450M+ consumers',2,NULL),(10,2,'Highly skilled workforce supported by the dual vocational education system',2,NULL),(11,2,'Low corruption and institutional stability attract long-term foreign investment',2,NULL),(12,3,'Massive manufacturing scale ÔÇö \'factory of the world\' producing ~28% of global manufactured output',3,NULL),(13,3,'Belt & Road Initiative extends infrastructure investment and geopolitical influence across 140+ countries',3,NULL),(14,3,'Largest population and consumer market ÔÇö 1.4B people with rapidly growing middle class',3,NULL),(15,3,'Rapid EV and renewable energy adoption positions China as global clean-tech leader',3,NULL),(16,3,'State-backed investment capacity enables long-horizon industrial policy without private-sector constraints',3,NULL),(17,4,'Agricultural superpower ÔÇö world\'s largest exporter of soybeans, beef, sugar and orange juice',4,NULL),(18,4,'Vast natural resources including the world\'s largest iron ore reserves and pre-salt offshore oil',4,NULL),(19,4,'Biodiversity and ecotourism potential from the Amazon basin provide long-run sustainable revenue',4,NULL),(20,4,'Young and growing population drives domestic consumption and labour supply',4,NULL),(21,4,'Regional geopolitical influence through Mercosur leadership and BRICS membership',4,NULL);
