INSERT INTO `SourceFieldReviews` VALUES (1,1,1,104,NULL,2,'https://www.sec.gov/Archives/edgar/data/320193/000032019326000013/aapl-20260328.htm','chars 12067-12280','Apple Inc.\nNotes to Condensed Consolidated Financial Statements (Unaudited)\nNote 1 ÔÇô Summary of Significant Accounting Policies\nBasis of Presentation and Preparation\nThe condensed consolidated financial statements','Iphone 2026',NULL,NULL,NULL,NULL,'2026-06-03 21:53:00.891774',NULL,NULL),(2,10,1,107,NULL,4,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 112379-112751','We are finalizing an investment and partnership agreement with OpenAI. There is no assurance that we will enter into an investment and partnership agreement with OpenAI or that a transaction will be completed.\nOur investment portfolio contains industry sector concentration risks, and a decline in any one or multiple industry sectors could increase our impairment losses.','CUSTOMER',NULL,NULL,NULL,NULL,'2026-06-03 21:53:44.125654',1,NULL),(3,10,1,107,NULL,2,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 112379-112751','We are finalizing an investment and partnership agreement with OpenAI. There is no assurance that we will enter into an investment and partnership agreement with OpenAI or that a transaction will be completed.\nOur investment portfolio contains industry sector concentration risks, and a decline in any one or multiple industry sectors could increase our impairment losses.','CHIPS',NULL,NULL,NULL,NULL,'2026-06-03 21:53:44.125654',1,NULL),(4,10,1,107,NULL,3,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 112379-112751','We are finalizing an investment and partnership agreement with OpenAI. There is no assurance that we will enter into an investment and partnership agreement with OpenAI or that a transaction will be completed.\nOur investment portfolio contains industry sector concentration risks, and a decline in any one or multiple industry sectors could increase our impairment losses.','OpenAI',NULL,NULL,NULL,NULL,'2026-06-03 21:53:44.125654',1,NULL),(5,10,1,107,NULL,1,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 115811-115895','For fiscal year 2026, sales to one direct customer represented 22% of total revenue ',NULL,NULL,NULL,NULL,NULL,'2026-06-03 21:53:44.125654',1,NULL),(6,10,1,110,NULL,2,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 112379-112588','We are finalizing an investment and partnership agreement with OpenAI. There is no assurance that we will enter into an investment and partnership agreement with OpenAI or that a transaction will be completed.','OpenAI',NULL,NULL,NULL,NULL,'2026-06-03 22:15:01.424993',1,NULL),(7,10,1,110,NULL,1,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 115665-116043','We have experienced periods where we receive a significant amount of our revenue from a limited number of customers, and this trend may continue. For fiscal year 2026, sales to one direct customer represented 22% of total revenue and sales to another direct customer represented 14% of total revenue, all of which were primarily attributable to the Compute & Networking segment.','22',NULL,NULL,NULL,NULL,'2026-06-03 22:15:01.424993',1,NULL),(8,10,1,112,NULL,2,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 112379-112588','We are finalizing an investment and partnership agreement with OpenAI. There is no assurance that we will enter into an investment and partnership agreement with OpenAI or that a transaction will be completed.','OpenAI',NULL,NULL,NULL,NULL,NULL,1,NULL),(9,10,1,112,NULL,1,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000021/nvda-20260125.htm','chars 115665-116043','We have experienced periods where we receive a significant amount of our revenue from a limited number of customers, and this trend may continue. For fiscal year 2026, sales to one direct customer represented 22% of total revenue and sales to another direct customer represented 14% of total revenue, all of which were primarily attributable to the Compute & Networking segment.','22',NULL,NULL,NULL,NULL,NULL,1,NULL),(10,10,1,112,NULL,0,'https://www.sec.gov/Archives/edgar/data/1045810/000104581026000052/nvda-20260426.htm','chars 66476-66755','Edge Computing revenue for the first quarter was $6.4 billion, up 29% from a year ago and up 10% sequentially. The increases were driven by robust Blackwell workstation demand, partially offset by slower consumer PC demand that was tempered by elevated memory and systems prices.','6400000000',NULL,NULL,NULL,NULL,NULL,6,NULL),(11,10,1,114,NULL,0,'POST /api/stock/refresh/10','chars 0-20','GPU revenue from Microsoft was $12B in FY2026','12000000000',NULL,NULL,NULL,NULL,'2026-06-03 22:29:32.000000',5,NULL),(12,1,1,115,NULL,2,'https://www.sec.gov/Archives/edgar/data/320193/000032019326000013/aapl-20260328.htm','selection','The Company is subject to various legal proceedings and claims that have arisen in the ordinary course of business and that have not been fully resolved.','value',NULL,NULL,NULL,NULL,'2026-06-05 18:05:58.710621',7,NULL),(13,23,1,118,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','selection','- **Revenue sources mentioned (without dollar or % values):** membership fees (ÔÇťattract and retain members,ÔÇŁ ÔÇťadjusting membership pricingÔÇŁ) and advertising (ÔÇťadvertising revenue,ÔÇŁ ÔÇťads on our serviceÔÇŁ).','Membership fees',NULL,NULL,NULL,NULL,'2026-06-04 18:23:48.692555',8,NULL),(14,23,1,120,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues','Streaming revenues',NULL,NULL,NULL,NULL,'2026-06-04 18:48:06.863171',8,NULL),(15,23,1,120,NULL,0,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','$45,183,036','45183036000',NULL,NULL,NULL,NULL,'2026-06-04 18:48:06.863171',8,NULL),(16,23,1,120,NULL,4,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues','PRODUCT',NULL,NULL,NULL,NULL,'2026-06-04 18:48:06.863171',8,NULL),(17,23,1,121,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues$45,183,036','Streaming revenues',NULL,NULL,NULL,NULL,NULL,8,NULL),(18,23,1,121,NULL,0,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues$45,183,036','45183036000',NULL,NULL,NULL,NULL,NULL,8,NULL),(19,23,1,121,NULL,4,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues','PRODUCT',NULL,NULL,NULL,NULL,NULL,8,NULL),(20,23,1,122,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','We primarily derive revenues from monthly membership fees for services related to streaming content to our members.','Membership fees',NULL,NULL,NULL,NULL,NULL,8,NULL),(21,23,1,122,NULL,0,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','Streaming revenues $45,183,036','45183036000',NULL,NULL,NULL,NULL,NULL,8,NULL),(22,23,2,NULL,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','If we fail to maintain a positive reputation concerning our service and the content we offer, including any advertisements, we may not be able to attract or retain members, we may face regulatory scrutiny and our operating results may be adversely affected.','Reputation Risk',NULL,NULL,NULL,NULL,NULL,8,1),(23,23,2,NULL,NULL,5,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','We believe that a positive reputation concerning our service is important in attracting and retaining members. To the extent our content, including any advertisements that may appear on our service, is perceived as low quality, offensive or otherwise not compelling to consumers, our ability to establish and maintain a positive reputation may be adversely impacted.','A negative reputation due to low-quality or offensive content could hinder member acquisition/retention, attract regulatory scrutiny, and harm operating results.',NULL,NULL,NULL,NULL,NULL,8,1),(24,23,2,NULL,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','difficulty of integrating solutions, operations, and personnel; inheriting liabilities and exposure to litigation; failure to realize anticipated benefits and expected synergies; and diversion of managementÔÇÖs time and attention','Acquisition and investment integration risks',NULL,NULL,NULL,NULL,NULL,8,2),(25,23,2,NULL,NULL,5,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','difficulty of integrating solutions, operations, and personnel; inheriting liabilities and exposure to litigation; failure to realize anticipated benefits and expected synergies; and diversion of managementÔÇÖs time and attention','Acquisitions may be difficult to integrate, may inherit liabilities, fail to realize expected benefits, and distract management, potentially harming business performance.',NULL,NULL,NULL,NULL,NULL,8,2),(26,23,2,NULL,NULL,2,'https://www.sec.gov/Archives/edgar/data/1065280/000106528026000034/nflx-20251231.htm','ai-suggested','if we do not complete an announced acquisition transaction or integrate an acquired business successfully and in a timely manner, we may not realize the benefits of the acquisition','Failure to complete or integrate acquisitions',NULL,NULL,NULL,NULL,NULL,8,3),(27,23,2,NULL,NULL,5,'https://www.sec.g